import FlowList from "./FlowList.js"

function App() {
  return (
    <div className="App">
      <header className="App-header">
        <h1>Yuuri Kurashima</h1>
        <p>do automation your things!</p>
        <BtnHeader/>
        <h2>Favorite Flows</h2>
        <h2>Flows</h2>
        <FlowList/>
      </header>
    </div>
  );
}

export default App;
